import { Router } from 'express';
import { z } from 'zod';
import { authenticate } from '../middleware/auth.js';
import { OrderModel, OrderStatus } from '../models/order.js';
import { AppError } from '../types/index.js';

export const ordersRouter = Router();

const CreateOrderSchema = z.object({
  userId: z.string().uuid(),
  items: z.array(z.object({
    productId: z.string().uuid(),
    quantity: z.number().int().positive(),
    unitPrice: z.number().positive(),
  })).min(1),
});

const UpdateStatusSchema = z.object({
  status: z.enum(['pending', 'processing', 'shipped', 'delivered', 'cancelled']),
});

ordersRouter.get('/', authenticate, async (req, res, next) => {
  try {
    const page = Number(req.query.page) || 1;
    const limit = Number(req.query.limit) || 20;
    const userId = typeof req.query.userId === 'string' ? req.query.userId : undefined;
    const orders = await OrderModel.findAll({ page, limit, userId });
    res.json({ data: orders, total: orders.length, page });
  } catch (err) { next(err); }
});

ordersRouter.get('/:id', authenticate, async (req, res, next) => {
  try {
    const order = await OrderModel.findById(req.params.id);
    if (!order) throw new AppError(404, 'Order not found');
    res.json({ data: order });
  } catch (err) { next(err); }
});

ordersRouter.post('/', authenticate, async (req, res, next) => {
  try {
    const parsed = CreateOrderSchema.safeParse(req.body);
    if (!parsed.success) throw new AppError(400, parsed.error.message);
    const order = await OrderModel.create({
      ...parsed.data,
      status: 'pending',
      totalAmount: parsed.data.items.reduce((sum, i) => sum + i.quantity * i.unitPrice, 0),
    });
    res.status(201).json({ data: order });
  } catch (err) { next(err); }
});

ordersRouter.patch('/:id/status', authenticate, async (req, res, next) => {
  try {
    const parsed = UpdateStatusSchema.safeParse(req.body);
    if (!parsed.success) throw new AppError(400, parsed.error.message);
    const order = await OrderModel.updateStatus(req.params.id, parsed.data.status as OrderStatus);
    if (!order) throw new AppError(404, 'Order not found');
    res.json({ data: order });
  } catch (err) { next(err); }
});

ordersRouter.delete('/:id', authenticate, async (req, res, next) => {
  try {
    const order = await OrderModel.findById(req.params.id);
    if (!order) throw new AppError(404, 'Order not found');
    await OrderModel.delete(req.params.id);
    res.status(204).send();
  } catch (err) { next(err); }
});

